    return (
            <div>
            <div className="home">
            <div style="width:100%;height:0;padding-bottom:57%;position:relative;"><iframe src="https://giphy.com/embed/z4Rl0fxSYfvKUzfJU1" width="100%" height="100%" style="position:absolute" frameBorder="0" class="giphy-embed" allowFullScreen></iframe></div><p><a href="https://giphy.com/gifs/games-pong-atari-z4Rl0fxSYfvKUzfJU1">via GIPHY</a></p>
                <h1 className="title"> PONG </h1>
                <button className="buttonGame">
                    <Link to="/Game" class="text-decoration-none text-dark">Play</Link>
                </button>
            </div>
        </div>

    );
}

export default Welcome_game;
